import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Renames a virtual room / location.
 * Payload: [virtualRoomId, newName]
 */
export class RenameVirtualRoomComposer
    implements IMessageComposer<(number | string)[]>
{
    private _data: (number | string)[];

    constructor(virtualRoomId: number, newName: string) {
        const id = Number.isFinite(virtualRoomId) ? virtualRoomId : 0;
        const name = String(newName ?? '')
            .trim()
            .slice(0, 32); // (optional) cap length
        this._data = [id, name];
        // console.debug('[RenameVirtualRoomComposer] sending', this._data);
    }

    public getMessageArray(): (number | string)[] {
        return this._data;
    }

    public dispose(): void {
        // no-op
    }
}
